#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char s[101];
        if (!fgets(s, sizeof(s), stdin)) break;
        s[strcspn(s, "\n")] = '\0'; // remove trailing newline
        char ch;
        scanf(" %c", &ch);
        getchar(); // consume newline after character
        int pos = -1;
        for (int i = 0; s[i] != '\0'; ++i) {
            if (s[i] == ch) { pos = i; break; }
        }
        printf("%d\n", pos);
    }
    return 0;
}

