#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin >> T)) return 0;
    string dummy; getline(cin, dummy); // consume endline after T
    for (int tc = 0; tc < T; ++tc) {
        string s; getline(cin, s);
        char ch; cin >> ch; getline(cin, dummy); // consume endline after character
        int pos = -1;
        for (size_t i = 0; i < s.size(); ++i) {
            if (s[i] == ch) { pos = static_cast<int>(i); break; }
        }
        cout << pos << '\n';
    }
    return 0;
}

